        {
          "slideTitle": "The Cell Boundary",
          "bulletPoints": [
            "Cell Membrane: Selectively permeable (All cells).",
            "Cell Wall: Rigid, protective (Plants only).",
            "Function: Shape and protection."
          ]
        },
        {
          "slideTitle": "The Control Center",
          "bulletPoints": [
            "Nucleus: The 'Brain' of the cell.",
            "Contains Chromosomes/DNA.",
            "Controls all life processes."
          ]
        }
      ]
    },
    "pdf": {
      "documentTitle": "Revision Notes: Cell Structure",
      "keyInformation": [
        "Definition of Prokaryotic vs Eukaryotic cells.",
        "Table comparing Plant and Animal cell features (Cell Wall, Nucleus).",
        "Functions of Membrane and Nucleus."
      ]
    },
    "docx": {
      "outlineTitle": "Teacher Lesson Plan: Session 1",
      "sections": [
