      ]
    }
  },
  "homework": {
    "task": "Interactive or practical homework task",
    "estimatedTimeMinutes": 30
  },
  "assessment": {
    "mcq": [
      {
        "question": "Who discovered the cell?",
        "options": [
          "A. Antonie van Leeuwenhoek",
          "B. Robert Hooke",
          "C. Rudolf Virchow",
          "D. Schleiden"
        ],
        "answer": "B",
        "explanation": "Robert Hooke observed cork cells in 1665 and coined the term 'cell'.",
        "marks": 1
      },
      {
        "question": "Which of the following is found ONLY in plant cells?",
        "options": [
          "A. Cell Membrane",
          "B. Nucleus",
          "C. Cell Wall",
          "D. Cytoplasm"
        ],
        "answer": "C",
        "explanation": "Cell walls are rigid outer layers present in plant cells but absent in animal cells.",
        "marks": 1
      },
      {
        "question": "The control center of the cell is:",
        "options": [
          "A. Mitochondria",
          "B. Nucleus",
          "C. Ribosome",
          "D. Vacuole"
        ],
        "answer": "B",
        "explanation": "The nucleus contains genetic material and controls cellular activities.",
        "marks": 1
      }
    ],
    "shortAnswer": [
      {
        "question": "Differentiate between Prokaryotic and Eukaryotic cells in terms of the nucleus.",
        "answer": "Prokaryotic cells lack a well-defined, membrane-bound nucleus; their genetic material is free-floating. Eukaryotic cells possess a true nucleus enclosed by a nuclear membrane that houses chromosomes.",
        "expectedLength": "2 clear points",
        "marks": 2,
        "rubric": [
          "1 mark for stating Prokaryotes lack a defined nucleus/membrane-bound nucleus.",
          "1 mark for stating Eukaryotes have a true membrane-bound nucleus."
        ]
      },
      {
        "question": "What is the function of the cell membrane?",
        "answer": "The cell membrane acts as a selectively permeable barrier that regulates the movement of substances (nutrients and waste) in and out of the cell, maintaining homeostasis.",
        "expectedLength": "2 clear points",
        "marks": 2,
        "rubric": [
          "1 mark for identifying it as a boundary/barrier regulating transport.",
          "1 mark for mentioning 'selectively permeable' or controlling entry/exit."
        ]
      }
    ],
    "longAnswer": [
      {
        "question": "Describe the structure and function of the nucleus. Why is it called the control center?",
        "answer": "The nucleus is a double-membrane bound organelle found in eukaryotic cells. It contains chromosomes made of DNA, which carry hereditary information. The nuclear membrane separates the nucleoplasm from the cytoplasm. It is called the 'control center' because it regulates all cellular activities (metabolism, growth) and controls heredity by directing protein synthesis via genetic instructions.",
        "expectedLength": "4-5 well-structured points with explanation",
        "marks": 5,
        "rubric": [
          "1 mark: Describes structure (double membrane bound).",
          "1 mark: Mentions presence of chromosomes/DNA/genetic material.",
          "1 mark: Explains separation from cytoplasm by nuclear envelope/membrane.",
          "1 mark: States function as 'control center' or regulator of activities.",
          "1 mark: Links DNA to heredity/protein synthesis."
        ]
      }
    ],
    "answerKey": {
      "mcq": [
        {
          "answer": "B",
          "explanation": "Robert Hooke discovered cells in cork (1665).",
          "marks": 1
        },
        {
          "answer": "C",
          "explanation": "Cell wall is unique to plant cells among the options.",
          "marks": 1
        },
        {
          "answer": "B",
          "explanation": "Nucleus contains DNA and controls cell functions.",
          "marks": 1
        }
      ],
      "shortAnswer": [
        {
          "answer": "Prokaryotes: No true nucleus (no membrane). Eukaryotes: True nucleus with nuclear envelope. Prokaryotic genetic material is free in cytoplasm.",
          "rubric": [
            "1 mark for correct distinction on presence of nucleus/membrane.",
            "1 mark for accurate description of location/state."
          ],
          "marks": 2
        },
        {
          "answer": "It is selectively permeable. It controls the entry and exit of materials like nutrients, gases, and waste products to maintain internal balance (homeostasis).",
          "rubric": [
            "1 mark for 'selectively permeable' or regulation concept.",
            "1 mark for specific function (entry/exit control)."
          ],
          "marks": 2
        }
      ],
      "longAnswer": [
        {
          "answer": "Structure: Double membrane bound, contains nucleoplasm and chromosomes. Function: Controls cell activities via DNA instructions; regulates heredity. Reason for 'Control Center': It directs metabolism and reproduction.",
          "rubric": [
            "1 mark: Structure (double membrane).",
            "1 mark: Content (chromosomes/DNA).",
            "1 mark: Separation from cytoplasm.",
            "1 mark: Control of activities/metabolism.",
            "1 mark: Heredity/Genetic link."
          ],
          "marks": 5
        }
      ],
      "generalMarkingGuidance": [
        "Award marks point-wise for each valid idea.",
        "Accept equivalent scientific wording if the meaning is correct (e.g., 'regulates' instead of 'controls').",
        "For long answers, reward structure and logical flow."
      ]
    }
  },
  "assignment": {
    "taskDescription": "Draw a labeled diagram comparing an Animal Cell and a Plant Cell. Highlight at least two differences in your drawing.",
    "rubric": [
      "Correct labeling of Nucleus, Membrane, Cytoplasm (2 marks).",
      "Accurate distinction: Cell Wall present in plant only (1 mark).",
      "Neatness and clarity of diagram (1 mark)."
    ],
    "answerKey": "Diagram must show a Plant cell with a thick outer wall and an Animal cell without it. Both must have labeled Nucleus, Membrane, Cytoplasm."
  }
}
